                                    // '&&' | '&=' | '(' | ')' | '*' | '**' | '*=' | '+' | '++' | '+=' | ',' | '-' |
                                    // '--' | '-=' | '/' | '/=' | ':' | ':=' | ';' | '<' | '<<' | '<<=' | '<=' | '=' |
                                    // '==' | '>' | '>=' | '>>' | '>>=' | '?' | '?=' | '[' | ']' | '^' | '^=' | '^^' |
                                    // 'async' | 'break' | 'case' | 'catch' | 'constructor' | 'continue' | 'default' |
                                    // 'do' | 'else' | 'export' | 'f32' | 'f64' | 'for' | 'foreach' | 'global' | 'i32' |
